import React, { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { createPortal } from 'react-dom';
import { useTranslation } from 'react-i18next';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { LoadingSpinner, FlagIcon } from '@/shared/components';
import CustomSelect from '@/shared/components/CustomSelect.jsx';
import { countries } from '@/shared/utils/constants/countries-with-flags.js';
import { disbursementService } from '@/features/disbursements/services';
import { securityService } from '@/features/settings/services';
import { createWalletTransferSchema, mapFieldErrors } from '@/shared/utils/validation/walletSchemas.js';
import { VerifyPinModal, SetPinPromptModal } from '@/features/settings/components';
import { useTransferRecipientSearch } from '@/features/wallet/hooks/useTransferRecipientSearch.js';
import { useTransferFeeCalculation } from '@/features/wallet/hooks/useTransferFeeCalculation.js';
import { useDisbursementServices } from '@/features/disbursements/hooks/useDisbursementServices.js';
import { useTransferSender } from '@/features/wallet/hooks/useTransferSender.js';
import { formatRecipientLabel, formatRecipientSubLabel, extractRecipientId, splitPhoneNumber, DEFAULT_COUNTRY_CODE } from '@/features/wallet/utils/transferUtils.js';
import { logger } from '@/shared/utils/logger.js';
import { useMutation } from '@/shared/hooks';
import { queryKeys } from '@/shared/utils/queryKeys.js';

const SUCCESS_COLOR = 'var(--success, #16a34a)';
const SUCCESS_BG = 'var(--success-bg, rgba(22, 163, 74, 0.12))';
const SUCCESS_HOVER = 'var(--success-hover, #15803d)';

const TransferFundsModal = ({ isOpen, onClose, onSuccess }) => {
  const { t } = useTranslation();
  const { success, error } = useToast();

  const [formData, setFormData] = useState({
    recipientQuery: '',
    phoneCountryCode: DEFAULT_COUNTRY_CODE,
    amount: '',
  });
  const [selectedRecipient, setSelectedRecipient] = useState(null);
  const [isPinModalOpen, setIsPinModalOpen] = useState(false);
  const [isCheckingPin, setIsCheckingPin] = useState(false);
  const [showSetPinPrompt, setShowSetPinPrompt] = useState(false);
  const [formErrors, setFormErrors] = useState({});
  const transferContextRef = useRef(null);
  
  // Determine if user is business account
  const isBusiness = useMemo(() => {
    try {
      const userData = JSON.parse(localStorage.getItem('userData') || '{}');
      return userData?.usertype?.toLowerCase() === 'business_contact';
    } catch {
      return false;
    }
  }, []);

  // Use React Query mutation for wallet transfer with automatic cache invalidation
  const transferMutation = useMutation({
    mutationFn: (payload) => disbursementService.transferWalletToWallet(payload),
    invalidateQueries: [
      queryKeys.wallet.all(), // Invalidate all wallet queries
      queryKeys.dashboard.metrics(), // Invalidate dashboard to show updated balance and transactions
    ],
    onSuccess: (response) => {
      if (response?.code === '00' || response?.success || response?.status === 'success') {
        success(t('transferSuccess', { ns: 'wallet' }));
        if (typeof onSuccess === 'function') {
          const context = transferContextRef.current;
          onSuccess({
            amount: context?.payload?.amount,
            recipient: context?.recipient,
            senderId: context?.payload?.['x-user-id'],
            response,
          });
        }
        resetState();
        transferContextRef.current = null;
        if (typeof onClose === 'function') {
          onClose();
        }
      } else {
        throw new Error(response?.message || t('transferFailed', { ns: 'wallet' }));
      }
    },
    onError: (err) => {
      logger.error('Wallet transfer failed', {
        error: err,
        errorCode: err?.code,
        responseCode: err?.response?.data?.code,
        dataCode: err?.data?.code
      });

      // Extract error code from various possible locations
      // Priority: err.code > err.response.data.code > err.data.code
      const errorCode = err?.code ||
        err?.response?.data?.code ||
        err?.data?.code;

      // Extract error message
      const errorMessage = err?.message || '';
      const responseMessage = err?.response?.data?.message ||
        err?.data?.message ||
        err?.response?.message || '';
      const fullMessage = errorMessage || responseMessage;

      // Check if this is an insufficient balance error
      // Code "07" with "User not found" message indicates insufficient balance for transfers
      const isInsufficientBalance =
        errorCode === '07' ||
        fullMessage.toLowerCase().includes('insufficient wallet balance') ||
        fullMessage.toLowerCase().includes('insufficient balance') ||
        (errorCode === '07' && fullMessage.toLowerCase().includes('user not found'));

      if (isInsufficientBalance) {
        error(t('insufficientBalance', { ns: 'wallet' }));
      } else {
        error(fullMessage || t('transferFailed', { ns: 'wallet' }));
      }

      transferContextRef.current = null;
    },
  });

  // Use custom hooks
  const { senderId } = useTransferSender();
  const {
    searchResults,
    isSearching,
    showResults,
    setShowResults,
    searchContainerRef,
    debouncedSearch,
    clearSearch,
  } = useTransferRecipientSearch();
  const { disbursementServiceId } = useDisbursementServices();
  const { feeData, isCheckingFee } = useTransferFeeCalculation(formData.amount, disbursementServiceId);

  const resetState = useCallback(() => {
    setFormData({
      recipientQuery: '',
      phoneCountryCode: DEFAULT_COUNTRY_CODE,
      amount: '',
    });
    setSelectedRecipient(null);
    clearSearch();
    setFormErrors({});
  }, [clearSearch]);

  useEffect(() => {
    if (!isOpen) {
      resetState();
    }
  }, [isOpen, resetState]);

  useEffect(() => {
    debouncedSearch(formData.recipientQuery, formData.phoneCountryCode);
  }, [formData.recipientQuery, formData.phoneCountryCode, debouncedSearch]);
  
  // Auto-select: whenever search finishes, pick the first result automatically.
  // Clear the selection only when search returns 0 results (i.e. no match found).
  // We do NOT depend on !selectedRecipient so this re-fires even mid-typing.
  useEffect(() => {
    if (isSearching) return; // wait for search to finish
    if (searchResults.length > 0) {
      const recipient = searchResults[0];
      logger.debug('Auto-select: search returned result, selecting', { displayName: recipient.displayName });
      setSelectedRecipient(recipient);
      setShowResults(false);
    } else if (formData.recipientQuery.trim().length >= 3) {
      // Query is long enough but no match found — clear stale selection
      setSelectedRecipient(null);
    }
  }, [searchResults, isSearching]);


  const handleChange = (e) => {
    const { name, value } = e.target;

    if (name === 'phoneCountryCode') {
      setFormData((prev) => ({
        ...prev,
        phoneCountryCode: value,
      }));
      setSelectedRecipient(null);
    } else {
      setFormData((prev) => ({
        ...prev,
        [name]: value,
      }));

      if (name === 'recipientQuery') {
        // Don't clear the recipient here — let the search results drive selection.
        // The auto-select useEffect will pick or clear the recipient based on results.
        setShowResults(true);
      }
    }

    if (formErrors[name]) {
      setFormErrors((prev) => {
        const next = { ...prev };
        delete next[name];
        return next;
      });
    }
  };

  const handleSelectRecipient = (recipient) => {
    setSelectedRecipient(recipient);

    const { countryCode, nationalNumber } = splitPhoneNumber(recipient?.phoneNumber, countries);

    setFormData((prev) => ({
      ...prev,
      phoneCountryCode: countryCode,
      recipientQuery: nationalNumber,
    }));
    setShowResults(false);
    setFormErrors((prev) => {
      if (!prev.recipient && !prev.recipientQuery) {
        return prev;
      }
      const next = { ...prev };
      delete next.recipient;
      delete next.recipientQuery;
      return next;
    });
  };

  const handleSubmit = async (event) => {
    event.preventDefault();

    if (transferMutation.isPending || isCheckingPin || isPinModalOpen) {return;}

    const schema = createWalletTransferSchema(t);
    const validation = schema.safeParse(formData);

    if (!validation.success) {
      const errors = mapFieldErrors(validation.error);
      setFormErrors(errors);
      const firstError = Object.values(errors)[0];
      if (firstError) {
        error(firstError);
      }
      return;
    }

    setFormErrors({});
    const validated = validation.data;

    // Transaction limit validation removed - users can now make transfers without verification level restrictions

    if (!selectedRecipient) {
      const message = t('transferRecipientRequired', { ns: 'wallet' });
      setFormErrors((prev) => ({ ...prev, recipient: message }));
      error(message);
      return;
    }

    if (!senderId || !disbursementServiceId) {
      error(
        !senderId 
          ? t('transferSenderRequired', {
              ns: 'wallet',
              defaultValue: 'Unable to determine your wallet account. Please sign in again or contact support.',
            })
          : t('transferServiceRequired', {
              ns: 'wallet',
              defaultValue: 'Disbursement service configuration not found. Please try again later.',
            })
      );
      return;
    }

    const recipientId = extractRecipientId(selectedRecipient);
    logger.debug('Recipient object debug', { recipientId, keys: Object.keys(selectedRecipient), userKeys: selectedRecipient?.user ? Object.keys(selectedRecipient.user) : [], recipient: selectedRecipient });

    // Use the exact amount the user typed (from formData), not the validated number or total with fees
    // This preserves the exact value and precision the user entered
    const amountToSend = formData.amount.trim();

    logger.debug('Wallet transfer payload preparation', {
      userTypedAmount: formData.amount,
      amountToSend,
      validatedAmount: validated.amount,
      feeDataTotal: feeData?.total,
    });

    transferContextRef.current = {
      payload: {
        'x-user-id': senderId, // Use x-user-id as property name to match header name
        amount: amountToSend, // Use the exact string value the user typed
        recipientId,
        serviceId: disbursementServiceId || undefined,
        currency: 'GHS',
        source: 'dashboard', 
      },
      recipient: selectedRecipient,
    };

    setIsCheckingPin(true);
    try {
      const resp = await securityService.getAccountSecurity();
      const sec = resp?.data || resp || {};
      const isPinSet = !!(
        sec.pinSet ||
        sec.hasPin ||
        sec.has_pin ||
        (sec.pin && sec.pin !== null && sec.pin !== 'null')
      );

      if (!isPinSet) {
        setShowSetPinPrompt(true);
        transferContextRef.current = null;
        setIsCheckingPin(false);
        return;
      }

      // Ensure modal opens and stop checking
      setIsPinModalOpen(true);
      setIsCheckingPin(false);
      logger.debug('PIN modal should open', { isPinModalOpen: true });
    } catch (err) {
      logger.error('Failed to check PIN status', { error: err });
      error(err?.message || t('unableToVerifyPin', { ns: 'wallet', defaultValue: 'Unable to verify PIN status. Please try again.' }));
      transferContextRef.current = null;
      setIsCheckingPin(false);
    }
  };

  const handleClose = useCallback(() => {
    if (transferMutation.isPending) {return;}
    resetState();
    if (typeof onClose === 'function') {
      onClose();
    }
  }, [transferMutation.isPending, onClose, resetState]);

  const hasSelectedRecipient = useMemo(
    () => !!(selectedRecipient && extractRecipientId(selectedRecipient)),
    [selectedRecipient]
  );

  const executeTransfer = useCallback(async () => {
    const context = transferContextRef.current;
    if (!context) {return;}

    // Execute mutation - onSuccess and onError are handled in mutation config
    transferMutation.mutate(context.payload);
    setIsPinModalOpen(false);
  }, [transferMutation]);

  const handlePinModalClose = useCallback(() => {
    setIsPinModalOpen(false);
    setIsCheckingPin(false);
    transferContextRef.current = null;
  }, []);

  const handlePinVerified = useCallback(() => {
    setIsPinModalOpen(false);
    executeTransfer();
  }, [executeTransfer]);

  const handleSetPinPromptClose = useCallback(() => {
    setShowSetPinPrompt(false);
  }, []);

  const selectedRecipientPhone = useMemo(() => {
    if (!selectedRecipient?.phoneNumber) {return '';}
    const { countryCode, nationalNumber } = splitPhoneNumber(selectedRecipient.phoneNumber, countries);
    return nationalNumber ? `${countryCode} ${nationalNumber}` : countryCode;
  }, [selectedRecipient]);

  return (
    <React.Fragment>
      {isOpen && createPortal(
        <div
          style={{
            position: 'fixed',
            inset: 0,
            backgroundColor: 'rgba(0,0,0,0.5)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            zIndex: 9999,
            backdropFilter: 'blur(4px)',
            padding: '16px',
            overflowY: 'auto'
          }}
        >
          <div
            style={{
              backgroundColor: 'var(--card)',
              borderRadius: 12,
              padding: 24,
              width: '100%',
              maxWidth: 440,
              boxShadow: 'var(--shadow-xl)',
              animation: 'slideIn 0.3s ease-out',
              transition: 'background-color var(--transition-theme)',
              margin: 'auto',
              maxHeight: '90vh',
              overflowY: 'auto',
            }}
          >
            <div
              style={{
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                marginBottom: 20,
              }}
            >
              <div
                style={{
                  width: 48,
                  height: 48,
                  borderRadius: '50%',
                  background: SUCCESS_COLOR,
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  marginBottom: 12,
                  boxShadow: '0 4px 12px rgba(22, 163, 74, 0.28)',
                }}
              >
                <span className="material-symbols-outlined" style={{ fontSize: 24, color: 'white' }}>
                  sync_alt
                </span>
              </div>
              {formErrors.phoneCountryCode && (
                <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '6px' }}>
                  {formErrors.phoneCountryCode}
                </p>
              )}
              {formErrors.recipientQuery && (
                <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '6px' }}>
                  {formErrors.recipientQuery}
                </p>
              )}
              {formErrors.recipient && (
                <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '6px' }}>
                  {formErrors.recipient}
                </p>
              )}
              <h3
                style={{
                  margin: 0,
                  marginBottom: 6,
                  color: 'var(--text-primary)',
                  fontSize: '20px',
                  fontWeight: 700,
                }}
              >
                {t('transferFunds', { ns: 'wallet' })}
              </h3>
              <p
                style={{
                  margin: 0,
                  color: 'var(--text-muted)',
                  fontSize: '13px',
                  textAlign: 'center',
                  lineHeight: '18px',
                }}
              >
                {t('walletToWalletDescription', { ns: 'wallet' })}
              </p>
            </div>

            <form onSubmit={handleSubmit}>
              <div style={{ marginBottom: 16 }} ref={searchContainerRef}>
                <label
                  style={{
                    display: 'block',
                    marginBottom: 8,
                    fontWeight: 600,
                    color: 'var(--text-primary)',
                    fontSize: '14px',
                  }}
                >
                  {t('searchRecipient', { ns: 'wallet' })}
                </label>
                <div style={{ display: 'flex', gap: '8px', alignItems: 'center', flexWrap: 'nowrap' }}>
                  <div style={{ position: 'relative', width: '120px', flexShrink: 0, minWidth: '120px' }}>
                    <span
                      style={{
                        position: 'absolute',
                        left: '10px',
                        top: '50%',
                        transform: 'translateY(-50%)',
                        pointerEvents: 'none',
                        zIndex: 1,
                        display: 'flex',
                        alignItems: 'center',
                      }}
                    >
                      <FlagIcon countryCode={countries.find((c) => c.dialCode === formData.phoneCountryCode)?.code || 'GH'} size="1em" />
                    </span>
                    <CustomSelect
                      name="phoneCountryCode"
                      value={formData.phoneCountryCode}
                      onChange={handleChange}
                      options={countries.map((country) => ({
                        value: country.dialCode,
                        label: country.dialCode,
                        name: country.name,
                        countryCode: country.code,
                      }))}
                      searchable
                      showCheckmark={false}
                      style={{ width: '100%' }}
                    />
                  </div>

                  <div style={{ position: 'relative', flex: 1 }}>
                    <input
                      name="recipientQuery"
                      value={formData.recipientQuery}
                      onChange={handleChange}
                      onFocus={() => setShowResults(true)}
                      placeholder={t('enterPhoneNumber', { ns: 'wallet', defaultValue: 'Enter phone number' })}
                      autoComplete="off"
                      inputMode="numeric"
                      pattern="[0-9]*"
                      style={{
                        width: '100%',
                        padding: '12px 40px 12px 14px',
                        fontSize: '14px',
                        borderRadius: 8,
                        border: `2px solid ${hasSelectedRecipient ? SUCCESS_COLOR : 'var(--border-secondary)'}`,
                        background: 'var(--bg-input)',
                        color: 'var(--text-primary)',
                        transition: 'all var(--transition-base)',
                        boxSizing: 'border-box',
                      }}
                    />
                    {formData.recipientQuery && (
                      <button
                        type="button"
                        onClick={() => {
                          setFormData((prev) => ({
                            ...prev,
                            recipientQuery: '',
                          }));
                          setSelectedRecipient(null);
                          clearSearch();
                          setFormErrors((prev) => {
                            if (!prev.recipient && !prev.recipientQuery) {
                              return prev;
                            }
                            const next = { ...prev };
                            delete next.recipient;
                            delete next.recipientQuery;
                            return next;
                          });
                        }}
                        style={{
                          position: 'absolute',
                          right: 12,
                          top: '50%',
                          transform: 'translateY(-50%)',
                          border: 'none',
                          background: 'transparent',
                          color: 'var(--text-muted)',
                          cursor: 'pointer',
                          padding: 4,
                        }}
                      >
                        <span className="material-symbols-outlined" style={{ fontSize: 18 }}>
                          close
                        </span>
                      </button>
                    )}
                    {showResults && formData.recipientQuery.trim().length >= 3 && (
                      <div
                        style={{
                          position: 'absolute',
                          top: 'calc(100% + 8px)',
                          left: 0,
                          right: 0,
                          background: 'var(--card)',
                          borderRadius: 12,
                          boxShadow: 'var(--shadow-lg)',
                          maxHeight: 280,
                          overflowY: 'auto',
                          zIndex: 10,
                          border: '1px solid var(--border-secondary)',
                        }}
                      >
                        {isSearching ? (
                          <div
                            style={{
                              padding: '16px',
                              color: 'var(--text-muted)',
                              fontSize: '14px',
                              textAlign: 'center',
                            }}
                          >
                            {t('searchingRecipients', { ns: 'wallet' })}
                          </div>
                        ) : searchResults.length === 0 ? (
                          <div
                            style={{
                              padding: '16px',
                              color: 'var(--text-muted)',
                              fontSize: '14px',
                              textAlign: 'center',
                            }}
                          >
                            {t('noRecipientsFound', { ns: 'wallet' })}
                          </div>
                        ) : (
                          searchResults.map((recipient) => {
                            const id = extractRecipientId(recipient);
                            const isActive = hasSelectedRecipient && id === extractRecipientId(selectedRecipient);
                            return (
                              <button
                                key={id || JSON.stringify(recipient)}
                                type="button"
                                onMouseDown={(event) => {
                                  event.preventDefault();
                                  handleSelectRecipient(recipient);
                                }}
                                style={{
                                  width: '100%',
                                  textAlign: 'left',
                                  border: 'none',
                                  background: isActive ? SUCCESS_BG : 'transparent',
                                  padding: '12px 16px',
                                  cursor: 'pointer',
                                  display: 'block',
                                  transition: 'background-color var(--transition-base)',
                                }}
                                onMouseEnter={(e) => {
                                  if (!isActive) {
                                    e.currentTarget.style.background = 'var(--bg-hover)';
                                  }
                                }}
                                onMouseLeave={(e) => {
                                  if (!isActive) {
                                    e.currentTarget.style.background = 'transparent';
                                  }
                                }}
                              >
                                <div
                                  style={{
                                    fontSize: '15px',
                                    fontWeight: 600,
                                    color: 'var(--text-primary)',
                                  }}
                                >
                                  {formatRecipientLabel(recipient) || t('unknownRecipient', { ns: 'wallet', defaultValue: 'Unknown Recipient' })}
                                </div>
                              </button>
                            );
                          })
                        )}
                      </div>
                    )}
                  </div>
                </div>
                {/* Show recipient info card when a recipient is selected */}
                {hasSelectedRecipient && (
                  <div
                    style={{
                      marginTop: 10,
                      padding: '10px 14px',
                      backgroundColor: SUCCESS_BG,
                      borderRadius: 8,
                      border: `1px solid ${SUCCESS_COLOR}`,
                      display: 'flex',
                      alignItems: 'center',
                      gap: 8,
                    }}
                  >
                    <span className="material-symbols-outlined" style={{ fontSize: 18, color: SUCCESS_COLOR }}>
                      person
                    </span>
                    <div style={{ flex: 1 }}>
                      <div
                        style={{
                          fontSize: '14px',
                          fontWeight: 600,
                          color: 'var(--text-primary)',
                        }}
                      >
                        {formatRecipientLabel(selectedRecipient) || t('unknownRecipient', { ns: 'wallet', defaultValue: 'Unknown Recipient' })}
                      </div>
                      <div
                        style={{
                          fontSize: '12px',
                          color: 'var(--text-muted)',
                          marginTop: 2,
                        }}
                      >
                        {selectedRecipientPhone || t('recipientSelected', { ns: 'wallet', defaultValue: 'Recipient selected' })}
                      </div>
                    </div>
                  </div>
                )}
                {formErrors.amount && (
                  <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '6px' }}>
                    {formErrors.amount}
                  </p>
                )}
              </div>

              <div style={{ marginBottom: 20 }}>
                <label
                  style={{
                    display: 'block',
                    marginBottom: 8,
                    fontWeight: 600,
                    color: 'var(--text-primary)',
                    fontSize: '14px',
                  }}
                >
                  {t('amount', { ns: 'wallet' })}
                </label>
                <div style={{ position: 'relative' }}>
                  <input
                    type="number"
                    name="amount"
                    value={formData.amount}
                    onChange={handleChange}
                    placeholder={t('amount', { ns: 'wallet' })}
                    min="0.01"
                    step="0.01"
                    style={{
                      width: '100%',
                      padding: '12px 46px 12px 14px',
                      fontSize: '15px',
                      fontWeight: 600,
                      borderRadius: 8,
                      border: `2px solid ${formData.amount ? SUCCESS_COLOR : 'var(--border-secondary)'}`,
                      background: 'var(--bg-input)',
                      color: formData.amount ? SUCCESS_COLOR : 'var(--text-primary)',
                      transition: 'all var(--transition-base)',
                      boxSizing: 'border-box',
                    }}
                  />
                  <span
                    style={{
                      position: 'absolute',
                      right: 16,
                      top: '50%',
                      transform: 'translateY(-50%)',
                      fontSize: '14px',
                      fontWeight: 600,
                      color: SUCCESS_COLOR,
                    }}
                  >
                    GHS
                  </span>
                </div>
              </div>

              {formData.amount && Number(formData.amount) > 0 && (
                <div
                  style={{
                    padding: '14px',
                    backgroundColor: SUCCESS_BG,
                    borderRadius: 10,
                    border: `1px solid ${SUCCESS_COLOR}`,
                    marginBottom: 20,
                    display: 'flex',
                    flexDirection: 'column',
                    gap: 10,
                  }}
                >
                  <div
                    style={{
                      display: 'flex',
                      justifyContent: 'space-between',
                      alignItems: 'center',
                    }}
                  >
                    <span
                      style={{
                        fontSize: '14px',
                        fontWeight: 600,
                        color: 'var(--text-primary)',
                      }}
                    >
                      {t('amountToTransfer', { ns: 'wallet' })}
                    </span>
                    <span
                      style={{
                        fontSize: '20px',
                        fontWeight: 700,
                        color: SUCCESS_COLOR,
                      }}
                    >
                      {t('currencyGHS', { ns: 'wallet' })}{' '}
                      {Number(formData.amount).toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                    </span>
                  </div>

                  {/* Fee Information */}
                  {isCheckingFee && (
                    <div
                      style={{
                        display: 'flex',
                        alignItems: 'center',
                        gap: 8,
                        fontSize: '13px',
                        color: 'var(--text-muted)',
                        padding: '8px 0',
                      }}
                    >
                      <LoadingSpinner size="small" />
                      <span>{t('calculatingFee', { ns: 'wallet', defaultValue: 'Calculating fee...' })}</span>
                    </div>
                  )}

                  {feeData && !isCheckingFee && feeData.total && (
                    <div
                      style={{
                        padding: '12px',
                        backgroundColor: 'var(--bg-tertiary)',
                        borderRadius: 8,
                        border: '1px solid var(--border-primary)',
                        display: 'flex',
                        flexDirection: 'column',
                        gap: 8,
                      }}
                    >
                      <div
                        style={{
                          display: 'flex',
                          justifyContent: 'space-between',
                          alignItems: 'center',
                          fontSize: '13px',
                        }}
                      >
                        <span style={{ color: 'var(--text-secondary)', fontWeight: 500 }}>
                          {t('transactionFee', { ns: 'wallet', defaultValue: 'Transaction Fee' })}
                        </span>
                        <span style={{ color: 'var(--text-primary)', fontWeight: 600 }}>
                          {t('currencyGHS', { ns: 'wallet' })}{' '}
                          {Number(feeData.feeApplied || feeData.fee || 0).toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                        </span>
                      </div>
                      <div
                        style={{
                          display: 'flex',
                          justifyContent: 'space-between',
                          alignItems: 'center',
                          fontSize: '14px',
                          paddingTop: '8px',
                          borderTop: '1px solid var(--border-primary)',
                        }}
                      >
                        <span style={{ color: 'var(--text-primary)', fontWeight: 600 }}>
                          {t('totalPayable', { ns: 'wallet', defaultValue: 'Total Payable' })}
                        </span>
                        <span style={{ color: SUCCESS_COLOR, fontWeight: 700 }}>
                          {t('currencyGHS', { ns: 'wallet' })}{' '}
                          {Number(feeData.total || feeData.totalPayable || formData.amount).toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                        </span>
                      </div>
                    </div>
                  )}

                  <div
                    style={{
                      display: 'flex',
                      justifyContent: 'space-between',
                      alignItems: 'center',
                      fontSize: '13px',
                      color: 'var(--text-primary)',
                    }}
                  >
                    <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-start', gap: 2 }}>
                      <span style={{ fontWeight: 600 }}>
                        {t('recipient', { ns: 'wallet', defaultValue: 'Recipient' })}
                      </span>
                      <span style={{ color: 'var(--text-muted)', fontSize: '12px' }}>
                        {selectedRecipientPhone || t('enterPhoneNumber', { ns: 'wallet', defaultValue: 'Enter phone number' })}
                      </span>
                    </div>
                    <span style={{ color: SUCCESS_COLOR, fontWeight: 600 }}>
                      {formatRecipientLabel(selectedRecipient) || t('transferRecipientRequired', { ns: 'wallet' })}
                    </span>
                  </div>

                  {hasSelectedRecipient && (
                    <div
                      style={{
                        display: 'flex',
                        alignItems: 'center',
                        gap: 8,
                        fontSize: '13px',
                        color: 'var(--text-muted)',
                      }}
                    >
                      <span className="material-symbols-outlined" style={{ fontSize: 16, color: SUCCESS_COLOR }}>
                        person
                      </span>
                      <span>
                        {t('transferRecipientLabel', {
                          ns: 'wallet',
                          recipient: formatRecipientLabel(selectedRecipient) || t('unknownRecipient', { ns: 'wallet' }),
                        })}
                      </span>
                    </div>
                  )}
                </div>
              )}

              <div style={{ display: 'flex', gap: 10 }}>
                <button
                  type="button"
                  onClick={handleClose}
                  disabled={transferMutation.isPending}
                  style={{
                    flex: 1,
                    padding: '12px 18px',
                    borderRadius: 8,
                    border: '2px solid var(--border-secondary)',
                    background: 'var(--bg-input)',
                    color: 'var(--text-primary)',
                    cursor: transferMutation.isPending ? 'not-allowed' : 'pointer',
                    fontSize: '14px',
                    fontWeight: 600,
                    transition: 'all var(--transition-base)',
                    opacity: transferMutation.isPending ? 0.5 : 1,
                  }}
                >
                  {t('cancel', { ns: 'wallet' })}
                </button>
                <button
                  type="submit"
                  disabled={transferMutation.isPending || !selectedRecipient || !formData.amount || Number(formData.amount) <= 0}
                  style={{
                    flex: 1,
                    padding: '12px 18px',
                    borderRadius: 8,
                    border: 'none',
                    background: (transferMutation.isPending || !selectedRecipient || !formData.amount || Number(formData.amount) <= 0)
                      ? 'var(--border-secondary)'
                      : SUCCESS_COLOR,
                    color: (transferMutation.isPending || !selectedRecipient || !formData.amount || Number(formData.amount) <= 0)
                      ? 'var(--text-muted)'
                      : 'var(--text-inverse)',
                    cursor: (transferMutation.isPending || !selectedRecipient || !formData.amount || Number(formData.amount) <= 0)
                      ? 'not-allowed'
                      : 'pointer',
                    fontSize: '14px',
                    fontWeight: 600,
                    transition: 'all var(--transition-base)',
                    boxShadow: (transferMutation.isPending || !selectedRecipient || !formData.amount || Number(formData.amount) <= 0)
                      ? 'none'
                      : 'var(--shadow-md)',
                    display: 'inline-flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    gap: 8,
                  }}
                  onMouseEnter={(e) => {
                    if (!transferMutation.isPending && selectedRecipient && formData.amount && Number(formData.amount) > 0) {
                      e.currentTarget.style.background = SUCCESS_HOVER;
                      e.currentTarget.style.boxShadow = 'var(--shadow-lg)';
                      e.currentTarget.style.transform = 'translateY(-1px)';
                    }
                  }}
                  onMouseLeave={(e) => {
                    if (!transferMutation.isPending && selectedRecipient && formData.amount && Number(formData.amount) > 0) {
                      e.currentTarget.style.background = SUCCESS_COLOR;
                      e.currentTarget.style.boxShadow = 'var(--shadow-md)';
                      e.currentTarget.style.transform = 'translateY(0)';
                    }
                  }}
                >
                  {transferMutation.isPending
                    ? t('processing', { ns: 'wallet' })
                    : t('send', { ns: 'wallet', defaultValue: 'Send' })
                  }
                </button>
              </div>
            </form>

            {isCheckingPin && (
              <div
                style={{
                  position: 'fixed',
                  top: 0,
                  left: 0,
                  right: 0,
                  bottom: 0,
                  backgroundColor: 'rgba(0, 0, 0, 0.4)',
                  backdropFilter: 'blur(3px)',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  zIndex: 10000,
                }}
              >
                <div
                  style={{
                    backgroundColor: 'var(--card)',
                    borderRadius: '16px',
                    padding: '40px',
                    boxShadow: 'var(--shadow-xl)',
                    display: 'flex',
                    flexDirection: 'column',
                    alignItems: 'center',
                    justifyContent: 'center',
                    minWidth: '120px',
                    minHeight: '120px',
                  }}
                >
                  <LoadingSpinner size="large" />
                  <div style={{ marginTop: 16, fontSize: '14px', color: 'var(--text-muted)' }}>
                    {t('checkingPinStatus', { ns: 'wallet', defaultValue: 'Checking your security PIN status…' })}
                  </div>
                </div>
              </div>
            )}

            {transferMutation.isPending && (
              <div
                style={{
                  position: 'fixed',
                  top: 0,
                  left: 0,
                  right: 0,
                  bottom: 0,
                  backgroundColor: 'rgba(0, 0, 0, 0.4)',
                  backdropFilter: 'blur(3px)',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  zIndex: 10000,
                }}
              >
                <div
                  style={{
                    backgroundColor: 'var(--card)',
                    borderRadius: '16px',
                    padding: '40px',
                    boxShadow: 'var(--shadow-xl)',
                    display: 'flex',
                    flexDirection: 'column',
                    alignItems: 'center',
                    justifyContent: 'center',
                    minWidth: '120px',
                    minHeight: '120px',
                  }}
                >
                  <LoadingSpinner size="large" />
                  <div style={{ marginTop: 16, fontSize: '14px', color: 'var(--text-muted)' }}>
                    {t('processing', { ns: 'wallet' })}
                  </div>
                </div>
              </div>
            )}

            <style>{`
          @keyframes slideIn {
            from {
              opacity: 0;
              transform: translateY(-20px) scale(0.95);
            }
            to {
              opacity: 1;
              transform: translateY(0) scale(1);
            }
          }

          select option {
            background-color: var(--bg-input);
            color: var(--text-primary);
          }

          input::placeholder {
            color: var(--text-muted);
            opacity: 0.6;
          }

          /* Tablet view (768px - 1024px) */
          @media (max-width: 1024px) and (min-width: 769px) {
            div[style*="maxWidth: 440"] {
              max-width: min(90vw, 400px) !important;
            }
            div[style*="padding: 24"] {
              padding: 20px !important;
            }
            div[style*="display: 'flex'"][style*="gap: '8px'"][style*="alignItems: 'center'"] {
              flex-wrap: nowrap !important;
            }
            div[style*="width: 120px"][style*="flexShrink: 0"],
            div[style*="width: 160px"][style*="flexShrink: 0"] {
              width: 110px !important;
              min-width: 110px !important;
            }
            input[style*="flex: 1"] {
              min-width: 0 !important;
            }
          }

          /* Mobile view (768px and below) */
          @media (max-width: 768px) {
            div[style*="maxWidth: 440"] {
              max-width: min(95vw, 360px) !important;
              margin: 16px !important;
            }
            div[style*="padding: 24"] {
              padding: 18px !important;
            }
            h3[style*="fontSize: '20px'"] {
              font-size: 18px !important;
            }
            div[style*="marginBottom: 20"] {
              margin-bottom: 14px !important;
            }
            div[style*="marginBottom: 16"] {
              margin-bottom: 12px !important;
            }
            div[style*="display: 'flex'"][style*="gap: '8px'"][style*="alignItems: 'center'"] {
              flex-wrap: nowrap !important;
              gap: 8px !important;
            }
            div[style*="width: 120px"][style*="flexShrink: 0"],
            div[style*="width: 160px"][style*="flexShrink: 0"] {
              width: 100px !important;
              min-width: 100px !important;
            }
            input[style*="padding: '12px"] {
              padding: 10px 14px !important;
              font-size: 14px !important;
              min-width: 0 !important;
              flex: 1 1 auto !important;
            }
            button[style*="padding: '12px"] {
              padding: 10px 16px !important;
              font-size: 13px !important;
            }
          }

          /* Small mobile view (480px and below) */
          @media (max-width: 480px) {
            div[style*="position: 'fixed'"][style*="inset: 0"] {
              padding: 8px !important;
              align-items: flex-start !important;
              padding-top: max(8px, env(safe-area-inset-top)) !important;
              padding-bottom: max(8px, env(safe-area-inset-bottom)) !important;
            }
            div[style*="maxWidth: 440"] {
              max-width: calc(100vw - 16px) !important;
              margin: 0 auto !important;
              border-radius: 12px !important;
            }
            div[style*="padding: 24"] {
              padding: 14px !important;
            }
            h3[style*="fontSize: '20px'"] {
              font-size: 16px !important;
            }
            p[style*="fontSize: '13px'"] {
              font-size: 11px !important;
            }
            div[style*="marginBottom: 20"] {
              margin-bottom: 12px !important;
            }
            div[style*="marginBottom: 16"] {
              margin-bottom: 10px !important;
            }
            div[style*="gap: 10"] {
              gap: 8px !important;
            }
            div[style*="gap: '8px'"] {
              gap: 6px !important;
            }
            input[style*="padding: '14px"] {
              padding: 10px 12px !important;
              font-size: 14px !important;
            }
            input[style*="padding: '12px"] {
              padding: 10px 12px !important;
              font-size: 14px !important;
            }
            button[style*="padding: '14px 20px'"] {
              padding: 10px 14px !important;
              font-size: 13px !important;
            }
            button[style*="padding: '12px"] {
              padding: 10px 14px !important;
              font-size: 13px !important;
            }
            div[style*="width: 48"][style*="height: 48"] {
              width: 40px !important;
              height: 40px !important;
            }
            span[style*="fontSize: 24"][style*="color: 'white'"] {
              font-size: 20px !important;
            }
            div[style*="width: 160px"][style*="flexShrink: 0"] {
              width: 110px !important;
              min-width: 110px !important;
            }
            label[style*="fontSize: '14px'"] {
              font-size: 13px !important;
            }
            div[style*="display: 'flex'"][style*="gap: '8px'"][style*="alignItems: 'center'"] {
              flex-wrap: nowrap !important;
              gap: 6px !important;
            }
            input[style*="padding: '12px"] {
              min-width: 0 !important;
              flex: 1 1 auto !important;
            }
            select[style*="padding: '12px"] {
              padding: 10px 24px 10px 28px !important;
              font-size: 13px !important;
            }
          }
        `}</style>
          </div>
        </div>,
        document.body
      )}
      {/* PIN Modal - Always render via portal so it can appear above the transfer modal */}
      {createPortal(
        <VerifyPinModal
          open={isPinModalOpen}
          onClose={handlePinModalClose}
          onVerified={handlePinVerified}
        />,
        document.body
      )}
      {/* Set PIN Prompt Modal */}
      {createPortal(
        <SetPinPromptModal open={showSetPinPrompt} onClose={handleSetPinPromptClose} />,
        document.body
      )}
    </React.Fragment>
  );
};

export default TransferFundsModal;

