/**
 * Custom Hook for Business Profile Completion Check
 * 
 * Checks if all required business profile fields are set for business accounts.
 * Required fields:
 * - Trading Name
 * - Registration Type
 * - Industry
 * - Date of Incorporation
 * - Registration Number
 * - TIN Number
 * - Business Email
 * - Business Phone
 * - GPS Address
 * 
 * Used to determine if the profile completion modal should be shown.
 */

import { useState, useEffect } from 'react';
import { useQuery } from '@/shared/hooks';
import { queryKeys } from '@/shared/utils/queryKeys.js';
import { logger } from '@/shared/utils/logger.js';

/**
 * Check if phone number is in valid format (country code + number)
 * Handles multiple formats: 233504336608, +233504336608, 0504336608, etc.
 */
const isValidPhoneFormat = (phone) => {
    if (!phone) {return false;}
    // Remove any spaces, dashes, parentheses, or plus signs
    const cleaned = phone.replace(/[\s\-\(\)\+]/g, '');
    // Check if it's a valid Ghana number:
    // - Starts with 233 and has 12 digits total (233 + 9 digits)
    // - Or starts with 0 and has 10 digits (local format)
    // - Or has 9 digits (assumed to be local without leading 0)
    return /^(233\d{9}|0\d{9}|\d{9})$/.test(cleaned);
};

/**
 * Check if a date is valid and not empty
 */
const isValidDate = (date) => {
    if (!date || date.trim() === '') {return false;}
    const dateObj = new Date(date);
    return !isNaN(dateObj.getTime());
};

export const useBusinessProfileCompletion = () => {
    const [shouldShowModal, setShouldShowModal] = useState(false);
    const [missingFields, setMissingFields] = useState([]);
    const [hasCheckedThisSession, setHasCheckedThisSession] = useState(false);

    // Get user data from localStorage
    const getUserData = () => {
        try {
            const userData = JSON.parse(localStorage.getItem('userData') || '{}');
            const userType = userData?.usertype || userData?.userType || userData?.user_type;
            const businessId = localStorage.getItem('businessId') ||
                userData?.businesses?.[0]?.id ||
                userData?.business?.id ||
                userData?.business_id ||
                userData?.businessId;


            return { userType, businessId };
        } catch (error) {
            logger.error('Error getting user data', { error });
            return { userType: null, businessId: null };
        }
    };

    const { userType, businessId } = getUserData();
    const isBusinessAccount = userType === 'business' || userType === 'business_contact';


    // Fetch business data directly
    const { data: businessData, isLoading } = useQuery({
        queryKey: queryKeys.settings.business(),
        endpoint: `/auth/business/${businessId}/business-info`,
        enabled: isBusinessAccount && !!businessId,
        staleTime: 5 * 60 * 1000, // 5 minutes
        select: (response) => {
            const businessInfo = response?.data || response || {};

            return {
                // Required fields for business profile completion
                tradingName: businessInfo.trading_name || '',
                registrationType: businessInfo.registration_type || '',
                industry: businessInfo.industry || '',
                dateOfIncorporation: businessInfo.date_of_incorporation || '',
                registrationNumber: businessInfo.registration_number || '',
                tinNumber: businessInfo.tin_number || '',
                businessEmail: businessInfo.business_email || '',
                businessPhone: businessInfo.business_phone || '',
                gpsAddress: businessInfo.gps_address || ''
            };
        },
    });

    useEffect(() => {
        // Only check for business accounts
        if (!isBusinessAccount) {
            setShouldShowModal(false);
            return;
        }

        // Wait for data to load
        if (isLoading || !businessData) {
            setShouldShowModal(false);
            return;
        }

        // Check if we've already checked this session and profile is complete
        // This prevents re-checking on every route change
        const sessionCheckKey = `businessProfileCheck_${businessId}`;
        const lastCheck = sessionStorage.getItem(sessionCheckKey);
        const lastCheckData = lastCheck ? JSON.parse(lastCheck) : null;
        
        // If we checked in this session and profile was complete, don't check again
        // Extended cache time to 30 minutes for complete profiles to reduce API calls
        if (lastCheckData && lastCheckData.isComplete && lastCheckData.timestamp > Date.now() - 30 * 60 * 1000) {
            logger.debug('Business profile already checked this session and is complete', {
                timestamp: lastCheckData.timestamp,
                age: Date.now() - lastCheckData.timestamp
            });
            setShouldShowModal(false);
            return;
        }
        
        // Check if reminder was dismissed recently (within 24 hours)
        // This check happens early to avoid unnecessary field validation if reminder is still active
        const reminderTime = localStorage.getItem('businessProfileReminderTime');
        if (reminderTime && Date.now() < parseInt(reminderTime)) {
            logger.debug('Business profile reminder dismissed, not showing modal yet', {
                reminderTime: parseInt(reminderTime),
                now: Date.now(),
                remaining: parseInt(reminderTime) - Date.now()
            });
            setShouldShowModal(false);
            return;
        }

        // Check which required fields are missing
        const missing = [];

        // 1. Trading Name (required)
        if (!businessData.tradingName || businessData.tradingName.trim() === '') {
            missing.push('tradingName');
        }

        // 2. Registration Type (required)
        if (!businessData.registrationType || businessData.registrationType.trim() === '') {
            missing.push('registrationType');
        }

        // 3. Industry (required)
        if (!businessData.industry || businessData.industry.trim() === '') {
            missing.push('industry');
        }

        // 4. Date of Incorporation (required)
        if (!isValidDate(businessData.dateOfIncorporation)) {
            missing.push('dateOfIncorporation');
        }

        // 5. Registration Number (required)
        if (!businessData.registrationNumber || businessData.registrationNumber.trim() === '') {
            missing.push('registrationNumber');
        }

        // 6. TIN Number (required)
        if (!businessData.tinNumber || businessData.tinNumber.trim() === '') {
            missing.push('tinNumber');
        }

        // 7. Business Email (required)
        if (!businessData.businessEmail || businessData.businessEmail.trim() === '') {
            missing.push('businessEmail');
        }

        // 8. Business Phone (required)
        if (!isValidPhoneFormat(businessData.businessPhone)) {
            missing.push('businessPhone');
        }

        // 9. GPS Address (required)
        if (!businessData.gpsAddress || businessData.gpsAddress.trim() === '') {
            missing.push('gpsAddress');
        }

        // If no fields are missing, NEVER show the modal (profile is complete)
        if (missing.length === 0) {
            logger.info('Business profile is complete - all required fields are filled', {
                checkedFields: {
                    tradingName: !!businessData.tradingName,
                    registrationType: !!businessData.registrationType,
                    industry: !!businessData.industry,
                    dateOfIncorporation: !!businessData.dateOfIncorporation,
                    registrationNumber: !!businessData.registrationNumber,
                    tinNumber: !!businessData.tinNumber,
                    businessEmail: !!businessData.businessEmail,
                    businessPhone: !!businessData.businessPhone,
                    gpsAddress: !!businessData.gpsAddress
                }
            });
            // Clear any reminder time since profile is now complete
            localStorage.removeItem('businessProfileReminderTime');
            // Cache the result for this session (extend cache time since profile is complete)
            sessionStorage.setItem(sessionCheckKey, JSON.stringify({
                isComplete: true,
                timestamp: Date.now()
            }));
            setShouldShowModal(false);
            setHasCheckedThisSession(true);
            return;
        }

        // Only show modal if we haven't shown it in this session already
        // This prevents the modal from appearing on every route change
        // But allow it to show again if reminder period has expired
        if (hasCheckedThisSession && missing.length > 0) {
            // Check if reminder was dismissed - if so, don't show again until reminder expires
            const reminderTime = localStorage.getItem('businessProfileReminderTime');
            if (reminderTime && Date.now() < parseInt(reminderTime)) {
                logger.debug('Already checked this session and reminder not expired, not showing modal again');
                setShouldShowModal(false);
                return;
            }
            // If reminder expired or never set, allow showing again but only once per session
            // Reset hasCheckedThisSession to allow showing after reminder expires
            if (!reminderTime || Date.now() >= parseInt(reminderTime)) {
                logger.debug('Reminder expired, allowing modal to show again this session');
            }
        }

        // Show modal because fields are missing and reminder period has expired (or never set)
        logger.info('Business profile incomplete, showing modal', { 
            missingFields: missing,
            missingCount: missing.length,
            allFields: {
                tradingName: businessData.tradingName || 'MISSING',
                registrationType: businessData.registrationType || 'MISSING',
                industry: businessData.industry || 'MISSING',
                dateOfIncorporation: businessData.dateOfIncorporation || 'MISSING',
                registrationNumber: businessData.registrationNumber || 'MISSING',
                tinNumber: businessData.tinNumber || 'MISSING',
                businessEmail: businessData.businessEmail || 'MISSING',
                businessPhone: businessData.businessPhone || 'MISSING',
                gpsAddress: businessData.gpsAddress || 'MISSING'
            }
        });
        setMissingFields(missing);
        setShouldShowModal(true);
        setHasCheckedThisSession(true);
        
        // Cache the check result
        sessionStorage.setItem(sessionCheckKey, JSON.stringify({
            isComplete: false,
            timestamp: Date.now(),
            missingFields: missing
        }));
    }, [isBusinessAccount, businessData, isLoading, businessId, hasCheckedThisSession]);

    return {
        shouldShowModal,
        missingFields,
        isBusinessAccount
    };
};
