const WalletBalanceChart = ({ apiData, t }) => {
  const chartRef = React.useRef(null);
  const { effectiveTheme } = useTheme();

  // Helper function to get computed CSS variable value
  const getCSSVariable = (varName) => {
    return getComputedStyle(document.documentElement).getPropertyValue(varName).trim();
  };

  React.useEffect(() => {
    let resizeTimer = null;
    const handleResize = () => {
      // Debounce resize events to prevent excessive chart resizing
      if (resizeTimer) {
        clearTimeout(resizeTimer);
      }
      resizeTimer = setTimeout(() => {
        if (chartRef.current?.chart) {
          chartRef.current.chart.resize();
        }
      }, 100);
    };

    window.addEventListener('resize', handleResize);
    return () => {
      window.removeEventListener('resize', handleResize);
      if (resizeTimer) {
        clearTimeout(resizeTimer);
      }
    };
  }, []);

  // Update chart when theme changes
  React.useEffect(() => {
    if (chartRef.current?.chart) {
      chartRef.current.chart.update();
    }
  }, [effectiveTheme]);

  const monthlyData = apiData?.monthly_data || [];
  const monthMap = { January: 0, February: 1, March: 2, April: 3, May: 4, June: 5, July: 6, August: 7, September: 8, October: 9, November: 10, December: 11 };

  // Get current date to determine year context
  const currentDate = new Date();
  const currentMonth = currentDate.getMonth();
  const currentYear = currentDate.getFullYear();

  // Process monthly data with year awareness
  const processedData = monthlyData.map(item => {
    const monthIndex = monthMap[item.month];
    let year = currentYear;

    // Check if API already provides year information
    if (item.year) {
      year = parseInt(item.year);
    } else {
      // Auto-detect year based on current date context
      // If month is in the future relative to current month, it's likely from previous year
      if (monthIndex > currentMonth) {
        year = currentYear - 1;
      }
    }

    return {
      month: item.month,
      monthIndex,
      year,
      inflow: parseFloat(item.inflow) || 0,
      outflow: parseFloat(item.outflow) || 0,
      sortKey: year * 100 + monthIndex // Combined year+month for sorting
    };
  });

  // Sort data chronologically
  const sortedData = processedData.sort((a, b) => a.sortKey - b.sortKey);

  // Determine if we have year transitions
  const uniqueYears = [...new Set(sortedData.map(item => item.year))];
  const hasYearTransition = uniqueYears.length > 1;

  // Extract and format data points directly from sorted monthly data
  const inflowData = sortedData.map(item => item.inflow);
  const outflowData = sortedData.map(item => item.outflow);

  // Generate labels matching the data points
  const labels = sortedData.map(item => {
    const monthShort = t(item.month.toLowerCase().substring(0, 3), { ns: 'dashboard' });
    return hasYearTransition ? `${monthShort} ${item.year.toString().slice(-2)}` : monthShort;
  });

  // Default labels for empty states
  const defaultLabels = [
    t('jan', { ns: 'dashboard' }),
    t('feb', { ns: 'dashboard' }),
    t('mar', { ns: 'dashboard' }),
    t('apr', { ns: 'dashboard' }),
    t('may', { ns: 'dashboard' }),
    t('jun', { ns: 'dashboard' }),
    t('jul', { ns: 'dashboard' }),
    t('aug', { ns: 'dashboard' }),
    t('sep', { ns: 'dashboard' }),
    t('oct', { ns: 'dashboard' }),
    t('nov', { ns: 'dashboard' }),
    t('dec', { ns: 'dashboard' })
  ];

  // Calculate data range for smart scaling
  const allValues = [...inflowData, ...outflowData].filter(val => val !== 0);
  const hasNonZeroValues = allValues.length > 0;
  const maxValue = hasNonZeroValues ? Math.max(...allValues, 1) : 100;
  const minValue = Math.min(...allValues, 0);

  // Get theme-aware colors
  const textColor = getCSSVariable('--text-primary');
  const mutedTextColor = getCSSVariable('--text-muted');
  const borderColor = getCSSVariable('--border-primary');
  const cardBg = getCSSVariable('--card');
  const accentColor = getCSSVariable('--accent');

  const data = {
    labels: labels.length > 0 ? labels : defaultLabels,
    datasets: [
      {
        label: t('incomingFunds', { ns: 'dashboard' }),
        data: inflowData,
        borderColor: '#10b981',
        backgroundColor: effectiveTheme === 'dark'
          ? 'rgba(16, 185, 129, 0.15)'
          : 'rgba(16, 185, 129, 0.1)',
        fill: true,
        tension: 0.4,
        pointRadius: 5,
        pointBackgroundColor: '#10b981',
      },
      {
        label: t('outgoingFunds', { ns: 'dashboard' }),
        data: outflowData,
        borderColor: accentColor,
        backgroundColor: effectiveTheme === 'dark'
          ? 'rgba(59, 130, 246, 0.15)'
          : 'rgba(0, 72, 149, 0.1)',
        fill: true,
        tension: 0.4,
        pointRadius: 5,
        pointBackgroundColor: accentColor,
      }
    ]
  };

  const options = {
    responsive: true,
    maintainAspectRatio: false,
    resizeDelay: 0,
    plugins: {
      legend: {
        position: 'top',
        labels: {
          boxWidth: 12,
          padding: 10,
          font: {
            size: 12
          },
          color: textColor,
          usePointStyle: true
        }
      },
      tooltip: {
        backgroundColor: cardBg,
        titleColor: textColor,
        bodyColor: textColor,
        borderColor: borderColor,
        borderWidth: 1,
        padding: 12,
        callbacks: {
          title: function (context) {
            const dataIndex = context[0].dataIndex;
            const label = context[0].label;

            // If we have year transition data, show enhanced title
            if (hasYearTransition && sortedData[dataIndex]) {
              const dataItem = sortedData[dataIndex];
              return `${dataItem.month} ${dataItem.year}`;
            }

            return label;
          },
          label: function (context) {
            let label = context.dataset.label || '';
            if (label) {
              label += ': ';
            }
            if (context.parsed.y !== null) {
              const value = context.parsed.y;
              const formattedValue = new Intl.NumberFormat('en-US', {
                style: 'currency',
                currency: 'GHS',
                minimumFractionDigits: 2,
                maximumFractionDigits: 2
              }).format(value);
              label += formattedValue;

              // Add additional context for very small values
              if (value > 0 && value < 100 && maxValue > 1000) {
                const percentage = ((value / maxValue) * 100).toFixed(1);
                label += ` (${percentage}% of max)`;
              }
            }
            return label;
          },
          afterLabel: function (context) {
            const messages = [];

            if (hasYearTransition) {
              messages.push('Showing data across multiple years');
            }

            return messages.length > 0 ? '\n' + messages.join('\n') : null;
          }
        }
      }
    },
    scales: {
      x: {
        ticks: {
          color: textColor,
          font: {
            size: 11,
            weight: '500'
          }
        },
        grid: {
          color: borderColor,
          drawBorder: false
        }
      },
      y: {
        type: 'linear',
        beginAtZero: true,
        ticks: {
          color: textColor,
          font: {
            size: 11,
            weight: '500'
          },
          callback: function (value, index, values) {
            return 'GH₵' + value.toLocaleString();
          }
        },
        grid: {
          color: borderColor,
          drawBorder: false
        },
        title: {
          display: true,
          text: t('amountGHS', { ns: 'dashboard' }),
          color: textColor,
          font: {
            size: 10,
            weight: '500'
          }
        }
      }
    }
  };

  return (
    <div className="invoices-card">
      <Line ref={chartRef} data={data} options={options} />
    </div>
  );
};

const Dashboard = () => {
  const { t } = useTranslation();
  const [currentPage, setCurrentPage] = useState(1);
  const [itemsPerPage] = useState(20);
  const navigate = useNavigate();
  const location = useLocation(); // Add useLocation hook
  const [windowWidth, setWindowWidth] = useState(window.innerWidth);
  const [showAddMoneyModal, setShowAddMoneyModal] = useState(false);

  // Check for navigation state or query params to open modal automatically
  useEffect(() => {
    const params = new URLSearchParams(location.search);
    const action = params.get('action');

    if (location.state?.openAddMoney || action === 'add-money') {
      // Small timeout to ensure component is fully ready
      setTimeout(() => {
        setShowAddMoneyModal(true);
        // Clear both state and query params so it doesn't reopen
        navigate(location.pathname, { replace: true, state: {} });
      }, 500);
    }
  }, [location.state, location.search, navigate, location.pathname]);
  const [showTransferFundsModal, setShowTransferFundsModal] = useState(false);
  const [showBusinessProfileModal, setShowBusinessProfileModal] = useState(false);
  const [isCheckingPin, setIsCheckingPin] = useState(false);
  const [showSetPinPrompt, setShowSetPinPrompt] = useState(false);
  const { searchTerm, updateSearch } = useSearch();

  // Check business profile completion on dashboard load
  // This hook automatically checks if business email and phone are set
  // and shows the modal only if fields are missing and reminder period has expired
  const { shouldShowModal, missingFields, isBusinessAccount } = useBusinessProfileCompletion();

  // Check if tour is active to prevent modal from showing during tour
  const { isTourOpen } = useTour();

  // Show modal when needed, but not during tour
  useEffect(() => {
    if (shouldShowModal && !isTourOpen) {
      setShowBusinessProfileModal(true);
    } else if (isTourOpen && showBusinessProfileModal) {
      // Close modal if tour opens while modal is showing
      setShowBusinessProfileModal(false);
    }
  }, [shouldShowModal, isTourOpen]);

  // Handle modal close - mark as dismissed so it doesn't show again for 24 hours
  // This ensures the popup doesn't keep appearing when user dismisses it
  const handleCloseBusinessProfileModal = () => {
    setShowBusinessProfileModal(false);
    // Set reminder time to 24 hours from now (user dismissed the modal)
    const reminderTime = Date.now() + (24 * 60 * 60 * 1000); // 24 hours
    localStorage.setItem('businessProfileReminderTime', reminderTime.toString());
    logger.debug('Business profile modal dismissed, reminder set for 24 hours');
  };

  const quickActions = getQuickActions(t);

  // Use React Query to fetch dashboard metrics with automatic caching and refetching
  const { data: dashboardResponse, isLoading: isLoadingMetrics, error: metricsError, refetch: refreshDashboardMetrics } = useQuery({
    queryKey: queryKeys.dashboard.metrics(),
    endpoint: '/auth/get-dashboard-metrics',
    staleTime: 1 * 60 * 1000, // 1 minute - data is fresh for 1 minute
    refetchOnWindowFocus: false, // Reduced from true - dashboard data doesn't need constant refetching
    refetchOnMount: true, // Refetch when component mounts (when navigating to dashboard)
    // DISABLED: refetchInterval was causing 8,640+ API calls per day per user!
    // refetchInterval: 10 * 1000, // Previously: Refetch every 10 seconds
    // Users can manually refresh using the refresh button if they need updated data
    onError: (error) => {
      logger.error('Failed to fetch dashboard metrics', { error });
    },
  });

  // Extract the actual data from the API response
  const apiData = dashboardResponse?.code === '00' ? dashboardResponse.data : null;
  const transactions = apiData?.transactions || [];

  // Calculate dynamic metrics based on API data
  const calculateMetrics = (apiData, t) => {
    const wallet_balance = apiData?.wallet_balance || '0';
    const available_balance = apiData?.available_balance;
    const wallet_currency = apiData?.wallet_currency || 'GHS';
    const total_collection = apiData?.total_collection || '0';
    const total_disbursement = apiData?.total_disbursement || '0';
    const net_cash_flow = apiData?.net_cash_flow || '0';

    const walletHint = generateMetricHint('Wallet Balance', wallet_balance, null, t);
    const collectionsHint = generateMetricHint('Total Collections', total_collection, null, t);
    const disbursementsHint = generateMetricHint('Total Disbursements', total_disbursement, null, t);
    const netHint = generateMetricHint('Net Cashflow', net_cash_flow, null, t);

    // Build available balance subtitle when it differs from wallet balance
    const availableHint = available_balance !== undefined && available_balance !== null
      ? `Available: ${formatCurrencyAmount(available_balance, wallet_currency)}`
      : null;

    return [
      {
        title: t('walletBalance', { ns: 'dashboard' }),
        value: formatCurrencyAmount(wallet_balance, wallet_currency),
        hint: availableHint,
        subtitle: null,
        trend: walletHint.trend,
        trendBadge: walletHint.badge,
        accent: '#22c55e',
        accentSoft: withAlpha('#22c55e', 0.18),
        accentStrong: withAlpha('#22c55e', 0.35),
        icon: 'account_balance_wallet'
      },
      {
        title: t('totalCollections', { ns: 'dashboard' }),
        value: formatCurrencyAmount(total_collection, wallet_currency),
        hint: collectionsHint.label,
        subtitle: null,
        trend: collectionsHint.trend,
        trendBadge: collectionsHint.badge,
        accent: '#0ea5e9',
        accentSoft: withAlpha('#0ea5e9', 0.18),
        accentStrong: withAlpha('#0ea5e9', 0.35),
        icon: 'call_received'
      },
      {
        title: t('totalDisbursements', { ns: 'dashboard' }),
        value: formatCurrencyAmount(total_disbursement, wallet_currency),
        hint: disbursementsHint.label,
        subtitle: null,
        trend: disbursementsHint.trend,
        trendBadge: disbursementsHint.badge,
        accent: '#f97316',
        accentSoft: withAlpha('#f97316', 0.18),
        accentStrong: withAlpha('#f97316', 0.35),
        icon: 'payments'
      },
      {
        title: t('netCashflow', { ns: 'dashboard' }),
        value: formatCurrencyAmount(net_cash_flow, wallet_currency),
        hint: netHint.label,
        subtitle: null,
        trend: netHint.trend,
        trendBadge: netHint.badge,
        accent: '#6366f1',
        accentSoft: withAlpha('#6366f1', 0.18),
        accentStrong: withAlpha('#6366f1', 0.35),
        icon: 'sync_alt'
      }
    ];
  };

  // Calculate metrics directly from apiData - no need for useState/useEffect
  const metrics = useMemo(() => calculateMetrics(apiData, t), [apiData, t]);

  // Handle window resize for responsive layout
  useEffect(() => {
    let resizeTimer = null;
    const handleResize = () => {
      // Debounce resize events to prevent excessive re-renders
      if (resizeTimer) {
        clearTimeout(resizeTimer);
      }
      resizeTimer = setTimeout(() => {
        setWindowWidth(window.innerWidth);
      }, 100);
    };

    window.addEventListener('resize', handleResize);
    return () => {
      window.removeEventListener('resize', handleResize);
      if (resizeTimer) {
        clearTimeout(resizeTimer);
      }
    };
  }, []);

  // Format transaction type to readable description
  // Memoize formatTransactionDescription to prevent recreation on every render
  const formatTransactionDescription = useCallback((transaction) => {
    const type = transaction.type?.toLowerCase() || '';
    const description = transaction.description || '';

    // If there's a description field, use it
    if (description) {
      return description;
    }

    // Otherwise, format the type
    const typeMap = {
      'disbursement': 'Disbursement',
      'transfer': 'Transfer',
      'utility': 'Utility',
      'deposit': 'Deposit',
      'collection': 'Collection',
      'invoice': 'Invoice',
      'credit': 'Credit',
      'debit': 'Debit',
      'payment': 'Payment',
      'payroll': 'Payroll',
      'sms': 'SMS',
      'wallet': 'Wallet'
    };

    // Try to match the type
    for (const [key, value] of Object.entries(typeMap)) {
      if (type.includes(key)) {
        return value;
      }
    }

    // Fallback: capitalize first letter of type
    return type ? type.charAt(0).toUpperCase() + type.slice(1) : 'Transaction';
  }, []);

  // Filter transactions based on search term
  const filteredTransactions = useMemo(() => {
    if (!searchTerm.trim()) {
      return transactions;
    }
    const term = searchTerm.toLowerCase();
    return transactions.filter(transaction =>
      transaction.reference?.toLowerCase().includes(term) ||
      transaction.type?.toLowerCase().includes(term) ||
      formatTransactionDescription(transaction).toLowerCase().includes(term) ||
      transaction.amount?.toString().includes(term) ||
      transaction.status?.toLowerCase().includes(term)
    );
  }, [transactions, searchTerm, formatTransactionDescription]);

  // Pagination logic
  const totalPages = Math.ceil(filteredTransactions.length / itemsPerPage);
  const startIndex = (currentPage - 1) * itemsPerPage;
  const endIndex = startIndex + itemsPerPage;
  const currentTransactions = filteredTransactions.slice(startIndex, endIndex);

  // Reset to first page when search changes
  useEffect(() => {
    setCurrentPage(1);
  }, [searchTerm]);

  const handlePageChange = (page) => {
    setCurrentPage(page);
  };

  const handleQuickActionClick = (actionName) => {
    logger.debug('Quick action clicked', { actionName });

    // Navigate to respective pages based on action
    const actionNames = {
      [t('addMoneyToWallet', { ns: 'dashboard' })]: () => setShowAddMoneyModal(true),
      [t('transferFunds', { ns: 'dashboard' })]: () => handleTransferFundsClick(),
      [t('monitorCollections', { ns: 'dashboard' })]: () => navigate('/collections'),
      [t('disburseFunds', { ns: 'dashboard' })]: () => navigate('/disbursements'),
      [t('runPayroll', { ns: 'dashboard' })]: () => navigate('/payroll'),
      [t('purchaseUtilities', { ns: 'dashboard' })]: () => navigate('/utilities'),
    };

    if (actionNames[actionName]) {
      actionNames[actionName]();
    } else {
      logger.warn('No navigation defined for quick action', { actionName });
    }
  };

  const handleTransferFundsClick = async () => {
    setIsCheckingPin(true);
    try {
      const resp = await securityService.getAccountSecurity();
      const sec = resp?.data || resp || {};
      const isPinSet = !!(
        sec.pinSet ||
        sec.hasPin ||
        sec.has_pin ||
        (sec.pin && sec.pin !== null && sec.pin !== 'null')
      );

      if (!isPinSet) {
        setShowSetPinPrompt(true);
      } else {
        setShowTransferFundsModal(true);
      }
    } catch (err) {
      logger.error('Failed to check PIN status', { error: err });
      // Fallback to opening the modal if check fails, let the modal handle it or show error
      // But for safety, maybe just show error toast
      // error(t('unableToVerifyPin', { ns: 'wallet' })); // Assuming error toast is available if we add it
      // For now, let's just log and maybe open the modal as fallback or do nothing
      // If we open modal, the modal's internal check might catch it or fail again.
      // Let's try to open the modal as fallback so user isn't completely blocked if API flakiness
      setShowTransferFundsModal(true);
    } finally {
      setIsCheckingPin(false);
    }
  };

  const getStatusChip = (status) => {
    // Normalize status to uppercase for consistent matching
    const normalizedStatus = (status || '').toUpperCase();

    const statusConfig = {
      SUCCESS: { class: 'paid', label: 'Success' },
      FAILED: { class: 'overdue', label: 'Failed' },
      PENDING: { class: 'sent', label: 'Pending' },
      PROCESSING: { class: 'sent', label: 'Pending' }, // Map processing to display as Pending
      sent: { class: 'sent', label: 'Sent' },
      paid: { class: 'paid', label: 'Paid' },
      overdue: { class: 'overdue', label: 'Overdue' },
      processing: { class: 'sent', label: 'Pending' }, // Map processing to display as Pending
      initiated: { class: 'sent', label: 'Initiated' } // Add initiated status support
    };

    // Check both normalized and original status
    const config = statusConfig[normalizedStatus] || statusConfig[status] || { class: 'sent', label: normalizedStatus || 'Unknown' };

    // Explicitly override label if we strictly want it to show as Pending for certain flows (handled by caller if needed)
    return <span className={`chip ${config.class}`}>{config.label}</span>;
  };

  return (
    <div className="dashboard-page">
      <section className="dashboard-metrics">
        {metrics.map((metric, index) => {
          // Map metric titles to tour data attributes
          const tourAttrMap = {
            [t('walletBalance', { ns: 'dashboard' })]: 'dashboard-wallet-balance',
            [t('totalCollections', { ns: 'dashboard' })]: 'dashboard-collections',
            [t('totalDisbursements', { ns: 'dashboard' })]: 'dashboard-disbursements',
            [t('netCashflow', { ns: 'dashboard' })]: 'dashboard-net-cashflow'
          };
          const tourAttr = tourAttrMap[metric.title] || null;

          return (
            <div key={metric.title} data-tour={tourAttr}>
              <MetricCard
                title={metric.title}
                value={metric.value}
                hint={metric.hint}
                icon={metric.icon}
                trend={metric.trend}
                trendBadge={metric.trendBadge}
                accent={metric.accent}
                accentSoft={metric.accentSoft}
                accentStrong={metric.accentStrong}
                className={windowWidth <= 768 ? 'centered' : ''}
              />
            </div>
          );
        })}
      </section>

      {/* Top Row - Chart and Quick Actions */}
      <section className="dashboard-content-row">
        {/* Chart Section */}
        <div className="dashboard-chart-section" data-tour="dashboard-chart">
          <WalletBalanceChart apiData={apiData} t={t} />
        </div>

        {/* Quick Actions Section - Responsive */}
        <aside className="side-card dashboard-quick-actions-aside" data-tour="dashboard-quick-actions">
          <div className="card-head dashboard-quick-actions-header">
            <h4>{t('quickActions', { ns: 'dashboard' })}</h4>
          </div>
          <div className="dashboard-quick-actions-list">
            {quickActions.map((action, index) => (
              <div
                key={index}
                className="dashboard-quick-action-item"
                onClick={() => handleQuickActionClick(action.name)}
              >
                <div
                  className="dashboard-action-icon"
                  style={{ backgroundColor: `${action.color}15` }}
                >
                  <span
                    className="material-symbols-outlined"
                    style={{ color: action.color, fontSize: '18px' }}
                  >
                    {action.icon}
                  </span>
                </div>
                <div className="dashboard-action-content">
                  <div className="dashboard-action-text">
                    {action.name}
                  </div>
                  <div className="dashboard-action-description">
                    {action.description}
                  </div>
                </div>
              </div>
            ))}
          </div>
        </aside>
      </section>

      {/* Modals */}
      {showSetPinPrompt && (
        <SetPinPromptModal
          open={showSetPinPrompt}
          onClose={() => setShowSetPinPrompt(false)}
        />
      )}

      {/* Loading Overlay for PIN Check */}
      {isCheckingPin && createPortal(
        <div style={{
          position: 'fixed',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          backgroundColor: 'rgba(0, 0, 0, 0.5)',
          backdropFilter: 'blur(4px)',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          zIndex: 10003
        }}>
          <div style={{
            backgroundColor: 'var(--card)',
            borderRadius: 'var(--radius-lg)',
            padding: '48px',
            boxShadow: 'var(--shadow-xl)',
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            justifyContent: 'center',
            minWidth: '120px',
            minHeight: '120px'
          }}>
            <LoadingSpinner size="large" />
          </div>
        </div>,
        document.body
      )}

      {/* Bottom Row - Recent Transactions Full Width */}
      <section className="dashboard-transactions-row">
        <div className="invoices-card dashboard-transactions-card" data-tour="dashboard-transactions">
          <div className="card-head">
            <h3>{t('recentTransactions', { ns: 'dashboard' })}</h3>
            <div className="head-actions">
              <span className="transaction-count">
                {t('showing', { ns: 'common' })} {startIndex + 1}-{Math.min(endIndex, filteredTransactions.length)} {t('of', { ns: 'common' })} {filteredTransactions.length} {t('transactions', { ns: 'dashboard' })}
              </span>
              <input
                className="small-search"
                placeholder={t('searchTransactions', { ns: 'dashboard' })}
                value={searchTerm}
                onChange={(e) => updateSearch(e.target.value)}
              />
            </div>
          </div>

          {/* Mobile Card View */}
          {windowWidth <= 768 ? (
            <div className="dashboard-transactions-mobile">
              {currentTransactions.map((transaction, index) => {
                const amountValue = typeof transaction.amount === 'string'
                  ? parseFloat(transaction.amount.replace(/[^0-9.-]/g, ''))
                  : Number(transaction.amount);

                const transactionType = transaction.type?.toLowerCase() || '';
                const serviceType = transaction.service_type?.toLowerCase() || '';
                const status = transaction.status?.toLowerCase() || '';
                const description = transaction.description?.toLowerCase() || '';

                // Explicitly check for disbursements and wallet transfers using service_type
                const isDisbursement = serviceType === 'disbursement' ||
                  transactionType === 'disbursement' ||
                  serviceType.includes('disbursement') ||
                  transactionType.includes('disbursement') ||
                  serviceType.includes('bank') || // Capture bank disbursements
                  transactionType.includes('bank') ||
                  description.includes('bank transfer') ||
                  description.includes('bank disbursement');

                const isWalletTransfer = serviceType === 'wallet_transfer' ||
                  serviceType === 'transfer' ||
                  transactionType === 'transfer' ||
                  transactionType === 'wallet_transfer' ||
                  (serviceType.includes('wallet') && serviceType.includes('transfer')) ||
                  (transactionType.includes('wallet') && transactionType.includes('transfer')) ||
                  description.includes('wallet transfer');

                // Determine direction (money in vs money out) — do NOT use status (SUCCESS/FAILED)
                // Status is shown separately as a chip; direction should reflect cashflow.
                const isReceived =
                  transactionType === 'deposit' ||
                  transactionType === 'collection' ||
                  transactionType === 'invoice' ||
                  transactionType === 'credit' ||
                  serviceType === 'deposit' ||
                  serviceType === 'collection' ||
                  serviceType === 'invoice' ||
                  (amountValue > 0 && !isDisbursement && !isWalletTransfer && !transactionType.includes('utility') && !serviceType.includes('utility'));

                const isSent =
                  isDisbursement ||
                  isWalletTransfer ||
                  transactionType === 'utility' ||
                  serviceType === 'utility' ||
                  transactionType === 'debit' ||
                  transactionType === 'payment' ||
                  amountValue < 0;

                const showSent = isSent;

                const formatDateTime = (dateString) => {
                  if (!dateString) { return '-'; }
                  const date = new Date(dateString);
                  return date.toLocaleString('en-US', {
                    month: 'short',
                    day: 'numeric',
                    hour: '2-digit',
                    minute: '2-digit'
                  });
                };

                const handleRowClick = () => {
                  logger.debug('Transaction row clicked', { transactionId: transaction.id });
                };

                return (
                  <div
                    key={transaction.id ? `${transaction.id}-${index}` : `${transaction.reference || 'tx'}-${index}`}
                    className="dashboard-transaction-card"
                    onClick={handleRowClick}
                  >
                    <div className="transaction-card-header">
                      <div className="transaction-card-icon">
                        {showSent ? (
                          <span className="tx-flow-icon tx-flow-icon--out" title="Money Out" aria-label="Money Out">
                            <FaArrowUp aria-hidden="true" />
                          </span>
                        ) : (
                          <span className="tx-flow-icon tx-flow-icon--in" title="Money In" aria-label="Money In">
                            <FaArrowDown aria-hidden="true" />
                          </span>
                        )}
                      </div>
                      <div className="transaction-card-main">
                        <div className="transaction-card-id">{transaction.reference}</div>
                        <div className="transaction-card-desc">{formatTransactionDescription(transaction)}</div>
                      </div>
                      <div className="transaction-card-amount">
                        {formatCurrencyAmount(transaction.amount, apiData?.wallet_currency || 'GHS')}
                      </div>
                    </div>
                    <div className="transaction-card-footer">
                      <div className="transaction-card-status">
                        {/* Force "Pending" display for specific bank disbursements if requested, or pass the actual status */}
                        {getStatusChip(
                          (isDisbursement && (transaction.channel === 'BANK' || description.includes('bank'))) && (status === 'success' || status === 'completed') === false ? 'PENDING' : transaction.status
                        )}
                      </div>
                      <div className="transaction-card-time">
                        {formatDateTime(transaction.date)}
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          ) : (
            /* Desktop Table View */
            <div className="dashboard-transactions-scroll">
              <table className="invoices-table dashboard-transactions-table" key={`page-${currentPage}`}>
                <thead>
                  <tr>
                    <th>{t('transactionId', { ns: 'dashboard', defaultValue: 'Transaction ID' })}</th>
                    <th>{t('description', { ns: 'dashboard', defaultValue: 'Description' })}</th>
                    <th>{t('amount', { ns: 'dashboard', defaultValue: 'Amount' })}</th>
                    <th>{t('status', { ns: 'dashboard', defaultValue: 'Status' })}</th>
                    <th>{t('time', { ns: 'dashboard', defaultValue: 'Time' })}</th>
                  </tr>
                </thead>
                <tbody>
                  {currentTransactions.map((transaction, index) => {
                    const amountValue = typeof transaction.amount === 'string'
                      ? parseFloat(transaction.amount.replace(/[^0-9.-]/g, ''))
                      : Number(transaction.amount);

                    const transactionType = transaction.type?.toLowerCase() || '';
                    const serviceType = transaction.service_type?.toLowerCase() || '';
                    const status = transaction.status?.toLowerCase() || '';
                    const description = transaction.description?.toLowerCase() || '';

                    // Explicitly check for disbursements and wallet transfers using service_type
                    const isDisbursement = serviceType === 'disbursement' ||
                      transactionType === 'disbursement' ||
                      serviceType.includes('disbursement') ||
                      transactionType.includes('disbursement') ||
                      serviceType.includes('bank') || // Capture bank disbursements
                      transactionType.includes('bank') ||
                      description.includes('bank transfer') ||
                      description.includes('bank disbursement');

                    const isWalletTransfer = serviceType === 'wallet_transfer' ||
                      serviceType === 'transfer' ||
                      transactionType === 'transfer' ||
                      transactionType === 'wallet_transfer' ||
                      (serviceType.includes('wallet') && serviceType.includes('transfer')) ||
                      (transactionType.includes('wallet') && transactionType.includes('transfer')) ||
                      description.includes('wallet transfer');

                    // Determine direction (money in vs money out) — do NOT use status (SUCCESS/FAILED)
                    const isReceived =
                      transactionType === 'deposit' ||
                      transactionType === 'collection' ||
                      transactionType === 'invoice' ||
                      transactionType === 'credit' ||
                      serviceType === 'deposit' ||
                      serviceType === 'collection' ||
                      serviceType === 'invoice' ||
                      (amountValue > 0 && !isDisbursement && !isWalletTransfer && !transactionType.includes('utility') && !serviceType.includes('utility'));

                    const isSent =
                      isDisbursement ||
                      isWalletTransfer ||
                      transactionType === 'utility' ||
                      serviceType === 'utility' ||
                      transactionType === 'debit' ||
                      transactionType === 'payment' ||
                      amountValue < 0;

                    const showSent = isSent;

                    const formatDateTime = (dateString) => {
                      if (!dateString) { return '-'; }
                      const date = new Date(dateString);
                      return date.toLocaleString('en-US', {
                        year: 'numeric',
                        month: 'short',
                        day: 'numeric',
                        hour: '2-digit',
                        minute: '2-digit'
                      });
                    };

                    const handleRowClick = () => {
                      logger.debug('Transaction details', { transaction });
                    };

                    return (
                      <tr
                        key={transaction.id ? `${transaction.id}-${index}` : `${transaction.reference || 'tx'}-${index}`}
                        onClick={handleRowClick}
                        style={{ cursor: 'pointer' }}
                      >
                        <td>
                          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                            {showSent ? (
                              <span className="tx-flow-icon tx-flow-icon--out tx-flow-icon--sm" title="Money Out" aria-label="Money Out">
                                <FaArrowUp aria-hidden="true" />
                              </span>
                            ) : (
                              <span className="tx-flow-icon tx-flow-icon--in tx-flow-icon--sm" title="Money In" aria-label="Money In">
                                <FaArrowDown aria-hidden="true" />
                              </span>
                            )}
                            <span>{transaction.reference}</span>
                          </div>
                        </td>
                        <td>{formatTransactionDescription(transaction)}</td>
                        <td>{formatCurrencyAmount(transaction.amount, apiData?.wallet_currency || 'GHS')}</td>
                        <td>
                          {getStatusChip(
                            (isDisbursement && (transaction.channel === 'BANK' || description.includes('bank'))) && (status === 'success' || status === 'completed') === false ? 'PENDING' : transaction.status
                          )}
                        </td>
                        <td>{formatDateTime(transaction.date)}</td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}

          {/* Pagination Component */}
          <Pagination
            currentPage={currentPage}
            totalItems={filteredTransactions.length}
            itemsPerPage={itemsPerPage}
            onPageChange={handlePageChange}
            showInfo={true}
          />
        </div>
      </section>

      {/* Add Money Modal */}
      {showAddMoneyModal && (
        <AddMoneyToWalletModal
          isOpen={showAddMoneyModal}
          onClose={() => setShowAddMoneyModal(false)}
        />
      )}

      {/* Transfer Funds Modal */}
      {showTransferFundsModal && (
        <TransferFundsModal
          isOpen={showTransferFundsModal}
          onClose={() => setShowTransferFundsModal(false)}
        />
      )}

      {/* Business Profile Completion Modal */}
      {isBusinessAccount && (
        <BusinessProfileCompletionModal
          isOpen={showBusinessProfileModal}
          onClose={handleCloseBusinessProfileModal}
          missingFields={missingFields}
        />
      )}
    </div>
  );
};

export default Dashboard;