/**
 * Business Profile Completion Modal
 * 
 * Displays a notification modal prompting business users to complete
 * their business email and phone number to unlock full application capabilities.
 */

import React from 'react';
import { createPortal } from 'react-dom';
import { useNavigate } from 'react-router-dom';
import { useTranslation } from 'react-i18next';

const BusinessProfileCompletionModal = ({ isOpen, onClose, missingFields }) => {
    const navigate = useNavigate();
    const { t } = useTranslation();

    if (!isOpen) {return null;}

    const handleGoToSettings = () => {
        // Set the active tab in localStorage to ensure the Business tab is opened
        localStorage.setItem('businessSettingsActiveTab', 'business');
        navigate('/settings/business#business');
        onClose();
    };

    const modalContent = (
        <div
            style={{
                position: 'fixed',
                top: 0,
                left: 0,
                right: 0,
                bottom: 0,
                backgroundColor: 'rgba(0, 0, 0, 0.85)',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                zIndex: 99999,
                padding: '20px',
                backdropFilter: 'blur(4px)'
            }}
            onClick={onClose}
        >
            <div
                style={{
                    backgroundColor: '#ffffff',
                    borderRadius: '16px',
                    maxWidth: '500px',
                    width: '100%',
                    padding: '32px',
                    boxShadow: '0 20px 60px rgba(0, 0, 0, 0.5)',
                    position: 'relative',
                    border: '1px solid var(--border-primary)'
                }}
                onClick={(e) => e.stopPropagation()}
            >
                {/* Icon */}
                <div
                    style={{
                        width: '64px',
                        height: '64px',
                        borderRadius: '50%',
                        backgroundColor: 'var(--accent-alpha)',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        margin: '0 auto 24px'
                    }}
                >
                    <span
                        className="material-symbols-outlined"
                        style={{
                            fontSize: '32px',
                            color: 'var(--accent)'
                        }}
                    >
                        business
                    </span>
                </div>

                {/* Title */}
                <h2
                    style={{
                        fontSize: '24px',
                        fontWeight: '700',
                        color: 'var(--text-primary)',
                        textAlign: 'center',
                        marginBottom: '16px'
                    }}
                >
                    {t('completeBusinessProfile', { ns: 'settings', defaultValue: 'Complete Your Business Profile' })}
                </h2>

                {/* Description */}
                <p
                    style={{
                        fontSize: '16px',
                        color: 'var(--text-secondary)',
                        textAlign: 'center',
                        marginBottom: '24px',
                        lineHeight: '1.6'
                    }}
                >
                    {t('businessProfileCompletionMessage', {
                        ns: 'settings',
                        defaultValue: 'To unlock the full capabilities of iSmartPay and ensure seamless access to all features including payments, collections, disbursements, and more, please complete your business profile'
                    })}
                </p>


                {/* Action Buttons */}
                <div
                    style={{
                        display: 'flex',
                        gap: '12px',
                        flexDirection: 'column'
                    }}
                >
                    <button
                        onClick={handleGoToSettings}
                        style={{
                            padding: '14px 24px',
                            backgroundColor: 'var(--accent)',
                            color: 'var(--text-inverse)',
                            border: 'none',
                            borderRadius: '8px',
                            fontSize: '16px',
                            fontWeight: '600',
                            cursor: 'pointer',
                            transition: 'all var(--transition-base)',
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            gap: '8px'
                        }}
                    >
                        <span className="material-symbols-outlined" style={{ fontSize: '20px' }}>
                            settings
                        </span>
                        {t('goToBusinessProfile', { ns: 'settings', defaultValue: 'Go to Business Profile' })}
                    </button>
                </div>
            </div>
        </div>
    );

    return createPortal(modalContent, document.body);
};

export default BusinessProfileCompletionModal;
